document.addEventListener("DOMContentLoaded",function(){const t=document.querySelectorAll('a[href^="tel:"]'),e=document.getElementById("ctad3-qr-popup"),c=document.getElementById("ctad3-qr-image"),n=document.getElementById("ctad3-qr-number");t.forEach(t=>{t.addEventListener("click",function(t){if(!("ontouchstart"in window||navigator.maxTouchPoints>0||navigator.msMaxTouchPoints>0)){t.preventDefault();const o=this.getBoundingClientRect(),a=this.getAttribute("href").replace("tel:","");c.src=`https://api.qrserver.com/v1/create-qr-code/?size=200x200&data=tel:${a}`,n.textContent=a,e.style.left=o.left+"px",e.style.top=o.bottom+window.scrollY+"px",e.classList.add("ctad3-active")}})}),document.querySelector(".ctad3-close").onclick=()=>e.classList.remove("ctad3-active"),document.addEventListener("click",function(t){e.contains(t.target)||t.target.closest('a[href^="tel:"]')||e.classList.remove("ctaf2-active")})});